mapper.select:
SELECT l.log_id, l.requested_by, l.request_type, l.input_data_json, l.prediction_result_json, l.created_at, u.name AS requestedByName FROM ai_prediction_log l LEFT JOIN admin_user u ON u.admin_id = l.requested_by
( l.requested_by LIKE CONCAT('%', #{q}, '%') OR l.request_type LIKE CONCAT('%', #{q}, '%') OR l.input_data_json LIKE CONCAT('%', #{q}, '%') OR l.prediction_result_json LIKE CONCAT('%', #{q}, '%') OR u.admin_name LIKE CONCAT('%', #{q}, '%') )
AND l.created_at >= #{from}
AND l.created_at < DATE_ADD(#{to}, INTERVAL 1 DAY)
ORDER BY l.created_at DESC
LIMIT #{cri.pageStart}, #{cri.perPageNum}
